+    /// Build an Anthropic SSE text response.
+    fn anthropic_text_sse(text: &str) -> RecordedResponse {
+        let msg_start = format!(
+            "event: message_start\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "message_start",
+                "message": {
+                    "id": "msg_verify_001",
+                    "type": "message",
+                    "role": "assistant",
+                    "model": TEST_MODEL,
+                    "content": [],
+                    "stop_reason": Value::Null,
+                    "stop_sequence": Value::Null,
+                    "usage": {"input_tokens": 20, "output_tokens": 1}
+                }
+            }))
+            .unwrap()
+        );
+        let block_start = format!(
+            "event: content_block_start\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "content_block_start",
+                "index": 0,
+                "content_block": {"type": "text", "text": ""}
+            }))
+            .unwrap()
+        );
+        let block_delta = format!(
+            "event: content_block_delta\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "content_block_delta",
+                "index": 0,
+                "delta": {"type": "text_delta", "text": text}
+            }))
+            .unwrap()
+        );
+        let block_stop = format!(
+            "event: content_block_stop\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "content_block_stop",
+                "index": 0
+            }))
+            .unwrap()
+        );
+        let msg_delta = format!(
+            "event: message_delta\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "message_delta",
+                "delta": {"stop_reason": "end_turn", "stop_sequence": Value::Null},
+                "usage": {"output_tokens": 10}
+            }))
+            .unwrap()
+        );
+        let msg_stop = format!(
+            "event: message_stop\ndata: {}\n\n",
+            serde_json::to_string(&json!({"type": "message_stop"})).unwrap()
+        );
+
+        RecordedResponse {
+            status: 200,
+            headers: vec![("Content-Type".to_string(), "text/event-stream".to_string())],
+            body_chunks: vec![
+                msg_start,
+                block_start,
+                block_delta,
+                block_stop,
+                msg_delta,
+                msg_stop,
+            ],
+            body_chunks_base64: None,
+        }
+    }
+
+    /// Build an Anthropic SSE tool call response.
+    fn anthropic_tool_sse(tool_name: &str, tool_args: &Value) -> RecordedResponse {
+        let args_str = serde_json::to_string(tool_args).unwrap_or_else(|_| "{}".to_string());
+        let msg_start = format!(
+            "event: message_start\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "message_start",
+                "message": {
+                    "id": "msg_verify_002",
+                    "type": "message",
+                    "role": "assistant",
+                    "model": TEST_MODEL,
+                    "content": [],
+                    "stop_reason": Value::Null,
+                    "stop_sequence": Value::Null,
+                    "usage": {"input_tokens": 25, "output_tokens": 1}
+                }
+            }))
+            .unwrap()
+        );
+        let block_start = format!(
+            "event: content_block_start\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "content_block_start",
+                "index": 0,
+                "content_block": {
+                    "type": "tool_use",
+                    "id": format!("toolu_verify_{tool_name}"),
+                    "name": tool_name,
+                    "input": {}
+                }
+            }))
+            .unwrap()
+        );
+        let block_delta = format!(
+            "event: content_block_delta\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "content_block_delta",
+                "index": 0,
+                "delta": {"type": "input_json_delta", "partial_json": args_str}
+            }))
+            .unwrap()
+        );
+        let block_stop = format!(
+            "event: content_block_stop\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "content_block_stop",
+                "index": 0
+            }))
+            .unwrap()
+        );
+        let msg_delta = format!(
+            "event: message_delta\ndata: {}\n\n",
+            serde_json::to_string(&json!({
+                "type": "message_delta",
+                "delta": {"stop_reason": "tool_use", "stop_sequence": Value::Null},
+                "usage": {"output_tokens": 12}
+            }))
+            .unwrap()
+        );
+        let msg_stop = format!(
+            "event: message_stop\ndata: {}\n\n",
+            serde_json::to_string(&json!({"type": "message_stop"})).unwrap()
+        );
+
+        RecordedResponse {
+            status: 200,
+            headers: vec![("Content-Type".to_string(), "text/event-stream".to_string())],
+            body_chunks: vec![
+                msg_start,
+                block_start,
+                block_delta,
+                block_stop,
+                msg_delta,
+                msg_stop,
+            ],
+            body_chunks_base64: None,
+        }
+    }
